import { NextResponse } from "next/server";
import { openai } from "@/lib/openai";
import hierarchicalCategories from "@/data/hierarchical-categories.json";
import productTypeCategories from "@/data/product-type-categories.json";

interface Category {
    id: string;
    name: string;
}

interface ProductTypeCategory {
    id: string;
    name: string;
    displayName: string;
}

interface Attribute {
    featureId: number;
    name: string;
    values: { valueId: number; name: string }[];
}

export async function POST(req: Request) {

    try {
        const { title, images, categories, attributes } = await req.json();

        // Title is optional if images are provided
        // if (!title) {
        //    return NextResponse.json({ error: "title is required" }, { status: 400 });
        // }

        if (!images || images.length === 0) {
            return NextResponse.json({ error: "at least one image is required" }, { status: 400 });
        }

        if (!categories || categories.length === 0) {
            return NextResponse.json({ error: "categories list is required" }, { status: 400 });
        }

        // Create category list for AI
        const categoryList = categories.map((c: Category) => `ID: ${c.id} - ${c.name}`).join("\n");

        // Create hierarchical categories list for AI
        const hierarchicalCategoryList = Object.entries(hierarchicalCategories).map(([mainCat, data]: [string, any]) => {
            const subcats = Object.entries(data.subcategories).map(([key, subdata]: [string, any]) => {
                return `  - ${subdata.name}: IDs [${subdata.ids.join(", ")}]`;
            }).join("\n");
            return `${data.name} (ID: ${data.id}):\n${subcats}`;
        }).join("\n\n");

        // Create product type categories list for AI
        const productTypeCategoryList = productTypeCategories.map((c: ProductTypeCategory) =>
            `ID: ${c.id} - ${c.name}`
        ).join("\n");

        // Create attributes list for AI
        const attributesList = attributes?.map((attr: Attribute) => {
            const values = attr.values.map(v => `${v.valueId}:${v.name}`).join(", ");
            return `${attr.featureId}. ${attr.name}: [${values}]`;
        }).join("\n") || "├ûzellik bilgisi yok";

        // Prepare image content for OpenAI Vision API
        // Images should be base64 encoded data URLs
        const imageContent = images.slice(0, 3).map((img: string) => ({
            type: "image_url",
            image_url: {
                url: img, // Should be base64 data URL or public URL
                detail: "low" // Use "low" for faster/cheaper analysis, "high" for detailed
            }
        }));

        const cleanTitle = title || "Belirtilmemi┼ş (G├Ârsellere g├Âre analiz et)";

        const prompt = `Sen uzman bir ├╝r├╝n s─▒n─▒fland─▒rma ve teknik analiz yapay zekas─▒s─▒n.
**G├ûREVLER:**
1. **KATEGOR─░ TESP─░T─░:** ├£r├╝n├╝n g├Ârselini analiz et ve a┼şa─ş─▒daki kategoriler aras─▒ndan EN DO─ŞRU olan─▒ se├ğ. Yanl─▒┼ş kategori se├ğimi kabul edilemez.
2. **TEKN─░K DETAY TESP─░T─░:** G├Ârseldeki ince detaylar─▒ (ba─şc─▒k, desen, topuk boyu, materyal) analiz et ve listedeki se├ğeneklerle e┼şle┼ştir.

**G─░RD─░LER:**
- **├£R├£N BA┼ŞLI─ŞI:** ${cleanTitle}
- **H─░YERAR┼Ş─░K KATEGOR─░ LISTESI (Sadece buradan se├ğ):**
${hierarchicalCategoryList}

- **├£R├£N T─░P─░ LISTESI (Sadece buradan se├ğ):**
${productTypeCategoryList}

- **TEKN─░K ├ûZELL─░K HAVUZU:**
${attributesList}

**ADIM 1: A├çIKLAMA (HTML)**
M├╝┼şteriyi ikna edecek, SEO uyumlu, "├ûzellik + Fayda" yap─▒s─▒nda madde madde a├ğ─▒klama yaz. (<ul><li>...</li></ul>)

**ADIM 2: KATEGOR─░ SE├ç─░M─░ (KR─░T─░K)**
- ├£r├╝n bir TERL─░K mi? O zaman "Terlik" kategorisini se├ğ. "Ayakkab─▒" se├ğme.
- ├£r├╝n bir BOT mu? O zaman "Bot" kategorisini se├ğ.
- Hiyerar┼şik kategoride en alt k─▒r─▒l─▒m─▒ (├Ârn: "Kad─▒n > Terlik > Parmak Aras─▒") bulmaya ├ğal─▒┼ş.

**ADIM 3: TEKN─░K ├ûZELL─░K E┼ŞLE┼ŞT─░RME (ZORUNLU)**
- "TEKN─░K ├ûZELL─░K HAVUZU"ndaki her bir ├Âzelli─şi tek tek kontrol et.
- G├Ârselde "C─▒rtl─▒" m─▒ g├Ârd├╝n? Listede "Kapama ┼Şekli" alt─▒nda "C─▒rtl─▒" varsa ID'sini al ve ekle.
- G├Ârselde "├çi├ğekli" mi g├Ârd├╝n? "Desen" alt─▒nda "├çi├ğekli" varsa ekle.
- **HEDEF:** En az 3-4 tane teknik ├Âzellik se├ğilmi┼ş olmal─▒.

**YANIT FORMATI (JSON):**
{
  "hierarchicalCategoryIds": ["ID1", "ID2", "ID3"],
  "hierarchicalCategoryName": "Kategori Ad─▒",
  "hierarchicalCategoryReason": "Neden bu kategori?",
  "productTypeCategoryId": "ID",
  "productTypeCategoryName": "─░sim",
  "productTypeCategoryReason": "Neden bu tip?",
  "descriptionHtml": "<ul><li>...</li></ul>",
  "attributeSelections": {
    "featureId": "valueId",
    "featureId2": "valueId2"
  }
}

**D─░KKAT:** 'attributeSelections' bo┼ş d├Ânemez. Mutlaka g├Ârselden bir ┼şeyler ├ğ─▒kar.`;

        const completion = await openai.chat.completions.create({
            model: "gpt-4o-mini", // Supports vision
            messages: [
                {
                    role: "system",
                    content: "Sen bir ├╝r├╝n analiz uzman─▒s─▒n. G├Ârsellerden ├Âzellikleri ├ğ─▒kar─▒p verilen listeyle e┼şle┼ştirirsin. EN ─░Y─░ TAHM─░N─░ yapmaktan ├ğekinme."
                },
                {
                    role: "user",
                    content: [
                        { type: "text", text: prompt },
                        ...imageContent
                    ]
                }
            ],
            response_format: { type: "json_object" },
            temperature: 0.2, // Daha kararl─▒, less random
            max_tokens: 4000
        });

        const analysis = JSON.parse(completion.choices[0].message.content || "{}");
        console.log("--- AI ANAL─░Z SONUCU ---");
        console.log(JSON.stringify(analysis, null, 2));
        console.log("-----------------------");

        // Validate hierarchical category
        if (!analysis.hierarchicalCategoryIds || !Array.isArray(analysis.hierarchicalCategoryIds)) {
            analysis.hierarchicalCategoryIds = ["37", "40", "46"];
            analysis.hierarchicalCategoryName = "Kad─▒n Sneaker";
            analysis.hierarchicalCategoryReason = "Otomatik se├ğildi (AI tahmini ge├ğersiz)";
        }

        // Validate product type category
        const selectedProductType = productTypeCategories.find(
            (c: ProductTypeCategory) => c.id === analysis.productTypeCategoryId
        );
        if (!selectedProductType) {
            analysis.productTypeCategoryId = productTypeCategories[0].id;
            analysis.productTypeCategoryName = productTypeCategories[0].name;
            analysis.productTypeCategoryReason = "Otomatik se├ğildi (AI tahmini ge├ğersiz)";
        } else {
            analysis.productTypeCategoryName = selectedProductType.name;
        }

        // Keep old categoryId for backward compatibility (use product type category)
        analysis.categoryId = analysis.productTypeCategoryId;
        analysis.categoryName = analysis.productTypeCategoryName;
        analysis.categoryReason = analysis.productTypeCategoryReason;

        return NextResponse.json({
            success: true,
            ...analysis
        });

    } catch (error: unknown) {
        console.error("AI Product Analysis Error:", error);
        const message = error instanceof Error ? error.message : "Unknown error";
        return NextResponse.json({ error: message }, { status: 500 });
    }
}

import { NextResponse } from "next/server";
import { adminDb } from "@/lib/firebase-admin";

export async function POST(req: Request) {
    try {
        const body = await req.json();
        const { productId, variants, galleryImages } = body;

        if (!productId || !variants || !Array.isArray(variants)) {
            return NextResponse.json({ error: "Missing required fields" }, { status: 400 });
        }

        const productRef = adminDb.collection("products").doc(productId);
        const productSnap = await productRef.get();

        if (!productSnap.exists) {
            return NextResponse.json({ error: "Product not found" }, { status: 404 });
        }

        const productData = productSnap.data();
        const parentSku = productData?.productCode || productData?.sku || productData?.barcode || "";

        // Yeni varyantlar─▒ formatla ve mevcutlara ekle
        const existingVariants = productData?.variants || [];
        const formattedVariants = variants.map((v: any) => ({
            ...v,
            sku: parentSku
        }));
        existingVariants.push(...formattedVariants);

        // Galeri resmini g├╝ncelle
        let updatedImages = productData?.images || [];
        if (galleryImages && Array.isArray(galleryImages)) {
            for (const img of galleryImages) {
                if (img && !updatedImages.includes(img)) {
                    updatedImages = [...updatedImages, img];
                }
            }
        }

        // 1. Firebase'e kaydet
        await productRef.update({ 
            variants: existingVariants,
            images: updatedImages
        });

        console.log(`[Add Variant] Ô£à Firebase kaydedildi. ${formattedVariants.length} yeni varyant eklendi. (SKU: ${parentSku})`);

        // 2. Ticimax'a otomatik g├Ânder (T─▒pk─▒ ├╝r├╝n g├Ânderir gibi t├╝m veriyi pushla)
        let ticimaxResult: any = null;
        try {
            // Fiyat─▒ formatla
            let priceObj = productData?.price;
            if (!priceObj || typeof priceObj !== "object") {
                priceObj = { sale: 0, purchase: 0, currency: "TL", tax: 10 };
            }
            if (!priceObj.sale && typeof productData?.price === "number") {
                priceObj = { sale: productData.price, purchase: 0, currency: "TL", tax: 10 };
            }

            // Kategori kontrol├╝ (Ticimax kategorisiz yeni ├╝r├╝n eklemeyi reddeder)
            const hasCategory = Number(productData?.categoryId) > 0;
            if (!hasCategory) {
                console.warn(`[Add Variant] Ticimax iptal: Kategori se├ğilmemi┼ş.`);
                return NextResponse.json({
                    success: true, 
                    message: `${formattedVariants.length} varyant eklendi.`,
                    variantCount: formattedVariants.length,
                    ticimax: { 
                        success: false, 
                        error: "├£r├╝ne Ticimax Kategorisi Se├ğilmemi┼ş!\nL├╝tfen ├╝r├╝n├╝ d├╝zenleyip bir Ticimax kategorisi se├ğin." 
                    }
                });
            }

            // Ticimax payload─▒n─▒ ├£r├╝n G├Ânder format─▒nda tam haz─▒rla
            const ticimaxPayload = {
                ...productData, // Firestore'daki di─şer t├╝m kategoriler ve ├Âzellikler dahil
                variants: existingVariants, // T├╝m varyantlar (eskiler + yeniler)
                images: updatedImages,
                price: {
                    sale: Number(priceObj.sale) || 0,
                    purchase: Number(priceObj.purchase) || 0,
                    currency: priceObj.currency || "TL",
                    tax: Number(priceObj.tax) || 10,
                }
            };

            const reqUrl = new URL(req.url);
            const baseUrl = `${reqUrl.protocol}//${reqUrl.host}`;

            console.log(`[Add Variant] Ticimax'a tam push g├Ânderiliyor... URL: ${baseUrl}/api/ticimax/push`);

            const pushRes = await fetch(`${baseUrl}/api/ticimax/push`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(ticimaxPayload)
            });

            let pushData;
            try {
                pushData = await pushRes.json();
            } catch {
                pushData = { success: false, error: "Parse hatas─▒: " + await pushRes.text() };
            }

            if (pushData.success) {
                console.log(`[Add Variant] Ô£à Ticimax g├╝ncellendi/eklendi! ID: ${pushData.ticimaxId}`);
                ticimaxResult = { success: true, ticimaxId: pushData.ticimaxId };
            } else {
                const rawXml = pushData.rawResponse || pushData.details || "";
                console.warn(`[Add Variant] ÔØî Ticimax hatas─▒:`, pushData.error);
                ticimaxResult = { success: false, error: pushData.error || "Ticimax hata d├Ând├╝rd├╝", rawResponse: rawXml.substring(0, 1000) };
            }
        } catch (err) {
            console.error("[Add Variant] Ticimax ba─şlant─▒ hatas─▒:", err);
            ticimaxResult = { success: false, error: `Ba─şlant─▒ hatas─▒: ${String(err)}` };
        }

        return NextResponse.json({
            success: true,
            message: `${formattedVariants.length} varyant eklendi.`,
            variantCount: formattedVariants.length,
            ticimax: ticimaxResult
        });
    } catch (error: unknown) {
        console.error("Add Variant Error:", error);
        return NextResponse.json(
            { error: error instanceof Error ? error.message : "Unknown error" },
            { status: 500 }
        );
    }
}

import { NextResponse } from 'next/server';
import { adminDb } from '@/lib/firebase-admin';
import path from 'path';

// Helper: XML Special Chars Escape
const escapeXml = (unsafe: string) => {
    return unsafe.replace(/[<>&'"]/g, function (c) {
        switch (c) {
            case '<': return '&lt;';
            case '>': return '&gt;';
            case '&': return '&amp;';
            case '\'': return '&apos;';
            case '"': return '&quot;';
            default: return c;
        }
    });
};

// Start SOAP Request Helper
async function fetchTicimax(action: string, soapBody: string) {
    const domain = process.env.TICIMAX_DOMAIN || "https://www.siteadi.com";
    const apiUrl = `${domain.replace(/\/$/, '')}/Servis/UrunServis.svc`;

    const response = await fetch(apiUrl, {
        method: 'POST',
        headers: {
            'Content-Type': 'text/xml; charset=utf-8',
            'SOAPAction': `http://tempuri.org/IUrunServis/${action}`
        },
        body: soapBody
    });

    return await response.text();
}

// Helper: Extract Items from XML using Regex
function extractItems(xml: string, tagName: string): any[] {
    const items: any[] = [];
    // Clean Namespaces
    const cleanXml = xml.replace(/<[a-zA-Z0-9_]+:/g, '<').replace(/<\/[a-zA-Z0-9_]+:/g, '</');

    const regex = new RegExp(`<${tagName}>([\\s\\S]*?)<\\/${tagName}>`, 'g');
    let match;

    while ((match = regex.exec(cleanXml)) !== null) {
        const block = match[1];
        const idMatch = block.match(/<ID>(\d+)<\/ID>/);
        const nameMatch = block.match(/<Tanim>(.*?)<\/Tanim>/);
        const featureIdMatch = block.match(/<OzellikID>(\d+)<\/OzellikID>/); // For Values

        if (idMatch && nameMatch) {
            items.push({
                id: idMatch[1],
                name: nameMatch[1],
                featureId: featureIdMatch ? featureIdMatch[1] : null
            });
        }
    }
    return items;
}

export async function POST() {
    try {
        const userCode = process.env.TICIMAX_USER;
        if (!userCode) {
            return NextResponse.json({ success: false, error: "API credentials missing" }, { status: 500 });
        }

        // 1. Fetch Features (Teknik Detay ├ûzellikleri)
        const featuresBody = `<?xml version="1.0" encoding="utf-8"?>
<soap:Envelope xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance" xmlns:xsd="http://www.w3.org/2001/XMLSchema" xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
  <soap:Body>
    <SelectTeknikDetayOzellik xmlns="http://tempuri.org/">
      <UyeKodu>${userCode}</UyeKodu>
      <f>
        <ID>0</ID>
        <Dil>tr</Dil>
      </f>
    </SelectTeknikDetayOzellik>
  </soap:Body>
</soap:Envelope>`;

        console.log("Fetching Features...");
        const featuresXml = await fetchTicimax('SelectTeknikDetayOzellik', featuresBody);

        // Custom extract for Features to get GrupID
        const features: any[] = [];
        const cleanFeaturesXml = featuresXml.replace(/<[a-zA-Z0-9_]+:/g, '<').replace(/<\/[a-zA-Z0-9_]+:/g, '</');
        const featureRegex = /<TeknikDetayOzellik>([\s\S]*?)<\/TeknikDetayOzellik>/g;
        let featMatch;
        while ((featMatch = featureRegex.exec(cleanFeaturesXml)) !== null) {
            const block = featMatch[1];
            const id = block.match(/<ID>(\d+)<\/ID>/)?.[1];
            const name = block.match(/<Tanim>(.*?)<\/Tanim>/)?.[1];
            const grpId = block.match(/<GrupID>(\d+)<\/GrupID>/)?.[1];

            if (id && name) {
                features.push({ id, name, groupId: grpId || "0" });
            }
        }

        console.log(`Found ${features.length} features.`);

        // 2. Fetch Values
        const valuesBody = `<?xml version="1.0" encoding="utf-8"?>
<soap:Envelope xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance" xmlns:xsd="http://www.w3.org/2001/XMLSchema" xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
  <soap:Body>
    <SelectTeknikDetayDeger xmlns="http://tempuri.org/">
      <UyeKodu>${userCode}</UyeKodu>
      <f>
        <ID>0</ID>
        <OzellikID>0</OzellikID>
        <Dil>tr</Dil>
      </f>
    </SelectTeknikDetayDeger>
  </soap:Body>
</soap:Envelope>`;

        console.log("Fetching Values...");
        const valuesXml = await fetchTicimax('SelectTeknikDetayDeger', valuesBody);

        const values: any[] = [];
        const cleanValuesXml = valuesXml.replace(/<[a-zA-Z0-9_]+:/g, '<').replace(/<\/[a-zA-Z0-9_]+:/g, '</');
        const valRegex = /<TeknikDetayDeger>([\s\S]*?)<\/TeknikDetayDeger>/g;
        let valMatch;
        while ((valMatch = valRegex.exec(cleanValuesXml)) !== null) {
            const block = valMatch[1];
            const id = block.match(/<ID>(\d+)<\/ID>/)?.[1];
            const name = block.match(/<Tanim>(.*?)<\/Tanim>/)?.[1];
            const fId = block.match(/<OzellikID>(\d+)<\/OzellikID>/)?.[1];

            if (id && name) {
                values.push({ id, name, featureId: fId });
            }
        }
        console.log(`Found ${values.length} values.`);

        // 3. Map Values to Features
        const attributesMapping = features.map(feature => {
            const featureValues = values.filter(v => v.featureId === feature.id).map(v => ({
                valueId: v.id,
                valueName: v.name
            }));

            return {
                featureId: feature.id,
                featureName: feature.name,
                groupId: feature.groupId || "0",
                values: featureValues
            };
        }); // Removed filter(f => f.values.length > 0) to debug/include all features

        // 4. Store in Firestore
        await adminDb.collection('settings').doc('attributes').set({
            list: attributesMapping,
            updatedAt: new Date().toISOString()
        });

        return NextResponse.json({
            success: true,
            message: "Attributes synced successfully to Firebase",
            counts: {
                features: features.length,
                values: values.length,
                mappedFeatures: attributesMapping.length
            }
        });

    } catch (error) {
        console.error("Sync Error:", error);
        return NextResponse.json({ success: false, error: String(error) }, { status: 500 });
    }
}

import { NextResponse } from 'next/server';

