// Yard─▒mc─▒: XML Karakter Temizleme
const escapeXml = (unsafe: string | number | undefined) => {
    if (unsafe === undefined || unsafe === null) return '';
    return String(unsafe)
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&apos;');
};

// Yard─▒mc─▒: XML'den De─şer ├çekme (Regex ile basit parse)
const extractValue = (xml: string, tag: string) => {
    const regex = new RegExp(`<${tag}>(.*?)<\/${tag}>`);
    const match = xml.match(regex);
    return match ? match[1] : null;
};

// Yard─▒mc─▒: XML'den Liste ├çekme (Namespace Temizleyerek)
const extractSuppliersFromXml = (xml: string) => {
