            if (innerIdMatch && parseInt(innerIdMatch[1]) > 0) {
                resultValue = innerIdMatch[1];
            }
        }

        if (parseInt(resultValue) > 0) {
            console.log(`[Ticimax Push] Ô£à Ba┼şar─▒l─▒! D├Ânen ID: ${resultValue}`);
            return NextResponse.json({ success: true, ticimaxId: resultValue });
        } else {
            console.log(`[Ticimax Push] ÔØî Ba┼şar─▒s─▒z. SaveUrunResult: ${resultValue}`);
            return NextResponse.json({ success: false, error: "Kaydedilemedi", details: responseText.substring(0, 2000) }, { status: 400 });
        }

    } catch (error) {
        console.error("Ticimax Push Error:", error);
        return NextResponse.json({ success: false, error: String(error) }, { status: 500 });
    }
}

import { NextResponse } from "next/server";
import { adminDb } from "@/lib/firebase-admin";

export const dynamic = 'force-dynamic';

export async function GET() {
    try {
        const snapshot = await adminDb.collection("products").get();
        let count = 0;
        const batch = adminDb.batch();
        snapshot.docs.forEach((doc: any) => {
            batch.delete(doc.ref);
            count++;
        });
        if (count > 0) {
            await batch.commit();
        }
        return NextResponse.json({ success: true, count });
    } catch (error: any) {
        return NextResponse.json({ success: false, error: error.message }, { status: 500 });
    }
}
